(()=>{"use strict";class t{constructor(){this.baseUrl="http://localhost:7071"}async request(t,e={},i=null){let s=`${this.baseUrl}?method=${t}`;e.id&&(s+=`&id=${e.id}`);const a={method:"GET",headers:{"Content-Type":"application/json"}};"createTicket"!==t&&"updateById"!==t||(a.method="POST",a.body=JSON.stringify(i));try{const t=await fetch(s,a);if(204===t.status)return null;if(!t.ok)throw new Error(`HTTP error ${t.status}`);const e=await t.text();return e?JSON.parse(e):null}catch(t){throw console.error("API Request failed:",t),t}}list(){return this.request("allTickets")}get(t){return this.request("ticketById",{id:t})}create(t){return this.request("createTicket",{},t)}update(t,e){return this.request("updateById",{id:t},e)}delete(t){return this.request("deleteById",{id:t})}}class e{constructor(){this.api=new t,this.tickets=[],this.currentEditId=null,this.currentDeleteId=null,this.init()}init(){this.cacheElements(),this.addEventListeners(),this.loadTickets()}cacheElements(){this.ticketsList=document.querySelector(".tickets-list"),this.loader=document.querySelector(".loader"),this.modalOverlay=document.querySelector(".modal-overlay"),this.modal=document.querySelector(".modal"),this.modalConfirm=document.querySelector(".modal-confirm"),this.modalTitle=document.querySelector(".modal-title"),this.modalForm=document.querySelector(".modal-form"),this.inputName=document.querySelector(".input-name"),this.inputDesc=document.querySelector(".input-desc"),this.cancelBtns=document.querySelectorAll(".cancel-btn"),this.addBtn=document.querySelector(".add-ticket-btn"),this.confirmDeleteBtn=document.querySelector(".modal-confirm .ok-btn")}addEventListeners(){this.addBtn.addEventListener("click",()=>this.openAddModal()),this.cancelBtns.forEach(t=>{t.addEventListener("click",()=>this.closeAllModals())}),this.modalOverlay.addEventListener("click",()=>this.closeAllModals()),this.modalForm.addEventListener("submit",t=>this.handleFormSubmit(t)),this.confirmDeleteBtn.addEventListener("click",()=>this.handleDelete())}async loadTickets(){this.showLoader();try{this.tickets=await this.api.list(),this.renderTickets()}catch(t){console.error("Failed to load tickets:",t),this.ticketsList.innerHTML='<div class="error">Ошибка загрузки. Убедитесь, что сервер запущен на порту 7070</div>'}finally{this.hideLoader()}}renderTickets(){0!==this.tickets.length?(this.ticketsList.innerHTML=this.tickets.map(t=>this.renderTicket(t)).join(""),this.tickets.forEach(t=>{const e=document.querySelector(`[data-id="${t.id}"]`);e&&(e.querySelector(".ticket-status").addEventListener("click",e=>{e.stopPropagation(),this.toggleStatus(t.id,!t.status)}),e.querySelector(".edit-btn").addEventListener("click",e=>{e.stopPropagation(),this.openEditModal(t.id)}),e.querySelector(".delete-btn").addEventListener("click",e=>{e.stopPropagation(),this.openDeleteModal(t.id)}),e.addEventListener("click",()=>this.toggleDescription(t.id)))})):this.ticketsList.innerHTML='<div class="empty">Нет тикетов</div>'}renderTicket(t){const e=new Date(t.created),i=`${e.getDate().toString().padStart(2,"0")}.${(e.getMonth()+1).toString().padStart(2,"0")}.${e.getFullYear().toString().slice(2)} ${e.getHours().toString().padStart(2,"0")}:${e.getMinutes().toString().padStart(2,"0")}`;return`\n      <div class="ticket" data-id="${t.id}">\n        <div class="ticket-status ${t.status?"completed":""}"></div>\n        <div class="ticket-content">\n          <div class="ticket-header">\n            <span class="ticket-name">${this.escapeHtml(t.name)}</span>\n            <span class="ticket-date">${i}</span>\n          </div>\n          <div class="ticket-description hidden">${this.escapeHtml(t.description||"")}</div>\n        </div>\n        <div class="ticket-actions">\n          <button class="btn-icon edit-btn" title="Редактировать">✎</button>\n          <button class="btn-icon delete-btn" title="Удалить">×</button>\n        </div>\n      </div>\n    `}escapeHtml(t){const e=document.createElement("div");return e.textContent=t,e.innerHTML}async toggleStatus(t,e){const i=this.tickets.find(e=>e.id===t);if(i)try{await this.api.update(t,{...i,status:e}),await this.loadTickets()}catch(t){console.error("Failed to toggle status:",t),alert("Ошибка при изменении статуса")}}async toggleDescription(t){const e=document.querySelector(`[data-id="${t}"]`),i=e.querySelector(".ticket-description");if(i.classList.contains("visible"))i.classList.remove("visible");else{if(!e._fullTicket)try{const s=await this.api.get(t);e._fullTicket=s,i.textContent=s.description||""}catch(t){return console.error("Failed to load ticket details:",t),void alert("Ошибка при загрузке описания")}i.classList.add("visible")}}openAddModal(){this.modalTitle.textContent="Добавить тикет",this.inputName.value="",this.inputDesc.value="",this.currentEditId=null,this.modal.classList.remove("hidden"),this.modalOverlay.classList.remove("hidden")}async openEditModal(t){if(this.tickets.find(e=>e.id===t))try{const e=await this.api.get(t);this.modalTitle.textContent="Изменить тикет",this.inputName.value=e.name,this.inputDesc.value=e.description||"",this.currentEditId=t,this.modal.classList.remove("hidden"),this.modalOverlay.classList.remove("hidden")}catch(t){console.error("Failed to load ticket for edit:",t),alert("Ошибка при загрузке данных тикета")}}openDeleteModal(t){this.currentDeleteId=t,this.modalConfirm.classList.remove("hidden"),this.modalOverlay.classList.remove("hidden")}closeAllModals(){this.modal.classList.add("hidden"),this.modalConfirm.classList.add("hidden"),this.modalOverlay.classList.add("hidden"),this.currentEditId=null,this.currentDeleteId=null}async handleFormSubmit(t){t.preventDefault();const e={name:this.inputName.value.trim(),description:this.inputDesc.value.trim()};if(e.name)try{if(this.currentEditId){const t=this.tickets.find(t=>t.id===this.currentEditId);await this.api.update(this.currentEditId,{...t,...e})}else await this.api.create({...e,status:!1});this.closeAllModals(),await this.loadTickets()}catch(t){console.error("Failed to save ticket:",t),alert("Ошибка сохранения")}else alert("Краткое описание обязательно")}async handleDelete(){if(this.currentDeleteId)try{await this.api.delete(this.currentDeleteId),this.closeAllModals(),await this.loadTickets()}catch(t){console.error("Failed to delete ticket:",t),alert("Ошибка удаления")}}showLoader(){this.loader&&this.loader.classList.remove("hidden")}hideLoader(){this.loader&&this.loader.classList.add("hidden")}}document.addEventListener("DOMContentLoaded",()=>{new e})})();